<section class="tsukie-product">
  <div class="tsukie-product-container">
    <!-- Left: Media -->
    <div class="tsukie-product-media">
      <div class="tsukie-main-image">
        {% if product.tags contains 'bestseller' %}
          <div class="tsukie-badge">BESTSELLER</div>
        {% endif %}
        <img id="tsukie-main-img" src="{{ product.featured_image | img_url: '1000x' }}" alt="{{ product.title | escape }}">
        <button class="tsukie-carousel-nav prev" onclick="tsukiePrevImage()">
          <svg fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M15 19l-7-7 7-7"></path></svg>
        </button>
        <button class="tsukie-carousel-nav next" onclick="tsukieNextImage()">
          <svg fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M9 5l7 7-7 7"></path></svg>
        </button>
      </div>
      <div class="tsukie-thumbnails">
        {% for image in product.images limit: 5 %}
          <div class="tsukie-thumb {% if forloop.first %}active{% endif %}" onclick="tsukieChangeImage('{{ image | img_url: '1000x' }}', {{ forloop.index0 }})">
            <img src="{{ image | img_url: '200x' }}" alt="{{ product.title }}">
          </div>
        {% endfor %}
      </div>
    </div>

    <!-- Right: Info -->
    <div class="tsukie-product-info">
      <div class="tsukie-product-header">
        <h1 class="tsukie-product-title">{{ product.title }}</h1>
        <button class="tsukie-wishlist" type="button">
          <svg fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 0 00-6.364 0z"></path></svg>
        </button>
      </div>

      {% if product.metafields.custom.subtitle %}
        <p class="tsukie-product-subtitle">{{ product.metafields.custom.subtitle }}</p>
      {% endif %}

      <div class="tsukie-rating-row">
        <div class="tsukie-stars">
          {% for i in (1..5) %}
            <svg viewBox="0 0 20 20"><path d="M10 15l-5.878 3.09 1.123-6.545L.489 6.91l6.572-.955L10 0l2.939 5.955 6.572.955-4.756 4.635 1.123 6.545z"/></svg>
          {% endfor %}
        </div>
        <div class="tsukie-rating-text">4.8 <span>84 reviews</span></div>
        <div class="tsukie-verified">VERIFIED PURCHASE</div>
      </div>

      <div class="tsukie-price-row">
        <div class="tsukie-price">{{ product.price | money }}</div>
        {% if product.compare_at_price > product.price %}
          <div class="tsukie-price-compare">{{ product.compare_at_price | money }}</div>
          <div class="tsukie-price-save">SAVE {{ product.compare_at_price | minus: product.price | money }}</div>
        {% endif %}
      </div>

      <div class="tsukie-emi">
        or <strong>{{ product.price | divided_by: 3 | money }}/month</strong> with easy EMI · No cost EMI on orders above ₹1,999
      </div>

      {% form 'product', product, class: 'tsukie-product-form', id: 'tsukie-product-form' %}
        <input type="hidden" name="id" value="{{ product.selected_or_first_available_variant.id }}" id="tsukie-variant-id">

        {% unless product.has_only_default_variant %}
          {% for option in product.options_with_values %}
            <div class="tsukie-variant-section">
              <div class="tsukie-variant-header">
                <div class="tsukie-variant-label">{{ option.name }}</div>
                {% if option.name == 'Color' %}
                  <div class="tsukie-variant-value" id="tsukie-selected-color">{{ option.selected_value }}</div>
                {% endif %}
                {% if option.name == 'Size' %}
                  <div class="tsukie-variant-value">— SELECT</div>
                {% endif %}
              </div>

              {% if option.name == 'Color' %}
                <div class="tsukie-color-swatches">
                  {% for value in option.values %}
                    <div 
                      class="tsukie-color-swatch {% if option.selected_value == value %}active{% endif %}" 
                      style="background-color: {{ value | downcase }};"
                      onclick="tsukieSelectColor('{{ value }}')"
                      data-value="{{ value }}"
                    ></div>
                  {% endfor %}
                </div>
              {% endif %}

              {% if option.name == 'Size' %}
                <div class="tsukie-size-options">
                  {% for value in option.values %}
                    <button 
                      type="button"
                      class="tsukie-size-btn {% if option.selected_value == value %}active{% endif %}"
                      onclick="tsukieSelectSize('{{ value }}')"
                      data-value="{{ value }}"
                    >{{ value }}</button>
                  {% endfor %}
                </div>
                <div class="tsukie-size-guide">
                  <svg width="14" height="14" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M9 7h6m0 10v-3m-3 3h.01M9 17h.01M9 14h.01M12 14h.01M15 11h.01M12 11h.01M9 11h.01M7 21h10a2 2 0 002-2V5a2 2 0 00-2-2H7a2 2 0 00-2 2v14a2 2 0 002 2z"></path></svg>
                  <a href="#size-guide">Find Your Size</a> — <a href="#size-guide">View Size Guide</a>
                </div>
              {% endif %}
            </div>
          {% endfor %}
        {% endunless %}

        {% if product.selected_or_first_available_variant.inventory_quantity < 10 %}
          <div class="tsukie-inventory">
            Only {{ product.selected_or_first_available_variant.inventory_quantity }} left in stock — selling fast
          </div>
        {% endif %}

        <div class="tsukie-btn-group">
          <button type="submit" name="add" class="tsukie-btn tsukie-btn-add">
            <svg fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z"></path></svg>
            ADD TO BAG
          </button>
          <button type="button" class="tsukie-btn tsukie-btn-buy" onclick="tsukieBuyNow()">BUY NOW</button>
        </div>
      {% endform %}

      <div class="tsukie-features">
        <div class="tsukie-feature">
          <svg fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z"></path></svg>
          <div class="tsukie-feature-title">PREMIUM FABRIC</div>
          <div class="tsukie-feature-text">100% Viscose</div>
        </div>
        <div class="tsukie-feature">
          <svg fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 0 01-15.357-2m15.357 2H15"></path></svg>
          <div class="tsukie-feature-title">EASY EXCHANGE</div>
          <div class="tsukie-feature-text">14 days</div>
        </div>
        <div class="tsukie-feature">
          <svg fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z"></path></svg>
          <div class="tsukie-feature-title">SECURE PAYMENT</div>
          <div class="tsukie-feature-text">UPI · Cards · COD</div>
        </div>
      </div>

      <div class="tsukie-accordion">
        <div class="tsukie-accordion-item">
          <div class="tsukie-accordion-header" onclick="tsukieToggleAccordion(this)">
            WHY YOU'LL LOVE IT
            <span class="tsukie-accordion-icon">+</span>
          </div>
          <div class="tsukie-accordion-content">
            <div style="padding-top:12px;">{{ product.description }}</div>
          </div>
        </div>
